powerpagecomponent.content:
{
  "type": 756150001,
  "value": "<div class="hero hero--login">
    <p class="hero-eyebrow hero-eyebrow--employee">Employee IT Support Portal</p>
    <h1>Welcome — please Register</h1>
    <p>Submit tickets, track issues and find answers in the knowledge base.</p>
</div>
<div id="login-error" style="
  display: none;
  width: 100%;
  max-width: 420px;
  margin: 0 auto 16px auto;
  padding: 12px 14px;
  border-radius: 8px;
  background-color: #fee2e2;
  border: 1px solid #fecaca;
  color: #991b1b;
  font-size: 12px;
  font-weight: 500;
">
</div>
<div class="login-body">
    <!-- <div class="tab-row"><button onclick="showTab('login',this)" class="tab-btn active">Login</button>
        <button
            onclick="showTab('register',this)" class="tab-btn">Register</button>
        </div> -->
    <!-- LOGIN VIEW -->
    <!-- REGISTER VIEW -->
    <div id="register-view" style="display: block;">
        <div class="login-card"
            style="max-width:400px; margin:auto; padding:20px; border:1px solid #ccc; border-radius:8px;">
            <div class="login-card-header" style="text-align:center; margin-bottom:20px;">
                <h3>Create your account</h3>
                <p>Register to get started</p>
            </div>
            <form onsubmit="return false;" class="login-form">

                <!-- Email -->
                <div class="form-group" style="margin-bottom:15px;">
                    <label for="reg-email">Email</label>
                    <input type="email" id="reg-email" placeholder="john.smith@company.com" required
                        style="width:100%; padding:8px;" />
                </div>

                <!-- Username -->
                <div class="form-group" style="margin-bottom:15px;">
                    <label for="reg-username">Username</label>
                    <input type="text" id="reg-username" placeholder="Username" required
                        style="width:100%; padding:8px;" />
                </div>

                <!-- Password -->
                <div class="form-group" style="margin-bottom:15px;">
                    <label for="reg-pass">Password</label>
                    <input type="password" id="reg-pass" placeholder="Min. 8 characters" required
                        style="width:100%; padding:8px;" />
                </div>

                <!-- Confirm Password -->
                <div class="form-group" style="margin-bottom:15px;">
                    <label for="reg-confirm">Confirm Password</label>
                    <input type="password" id="reg-confirm" placeholder="Re-enter password" required
                        style="width:100%; padding:8px;" />
                </div>

                <!-- Captcha Image -->
                <div class="form-group" style="margin-bottom:15px; text-align:center;">
                    <label for="captcha">Captcha</label><br>
                    <img id="customCaptcha" src="add source here" alt="Captcha"
                        style="height:50px;width:180px;display:block;margin-bottom:5px;" /><br>
                    <button type="button" id="refreshCaptcha"
                        style="padding:5px 10px; background:#f0f0f0; border:1px solid #ccc; border-radius:4px; cursor:pointer;">
                        Generate New Image
                    </button><br><br>
                    <input type="text" id="captcha-code" placeholder="Enter code from image" required
                        style="width:100%; padding:8px;" />
                </div>

                <!-- Register Button -->
                <button type="submit" class="primary-btn" id="rgstrBtn"
                    style="width:100%; padding:10px; background:#0078D4; color:white; border:none; border-radius:4px; cursor:pointer;">
                    Register
                </button>
            </form>
        </div>
    </div>
</div>
<div class="row sectionBlockLayout text-start"
    style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
    <div class="container" style="padding: 0px; display: flex; flex-wrap: wrap;">
        <div class="col-lg-12 columnBlockLayout"
            style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px;"></div>
    </div>
</div>
<footer class="site-footer site-footer--employee">
    <p class="footer-copy--employee">IT Support Portal &copy; 2025 &mdash; Powered by Microsoft Power Pages</p>
    <div class="footer-links footer-links--employee">
        <a href="#">ext. 1234</a>
        <a href="#">Email IT</a>
        <a href="#">Privacy</a>
    </div>
</footer>

<script>
    // function showTab(tab, btn) {
    //     document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    //     btn.classList.add('active');
    //     document.getElementById('login-view').style.display = tab === 'login' ? 'block' : 'none';
    //     document.getElementById('register-view').style.display = tab === 'register' ? 'block' : 'none';
    // }
    // function switchToRegister() { showTab('register', document.querySelectorAll('.tab-btn')[1]); }
    // function switchToLogin() { showTab('login', document.querySelectorAll('.tab-btn')[0]); }

    $(document).ready(function () {
        //$("ul.nav-account").hide();
        //$(".row > .col-md-6").hide();
        //$("#ContentContainer_MainContent_MainContent_SecureRegister").hide();
        document.getElementById("mainContent").style.marginTop = "0px";
        setTimeout(function () {
            var originalCaptchaSrc = $("#ctl00_ctl00_ContentContainer_MainContent_MainContent_captcha_CaptchaImageUP").attr("src");

            if (originalCaptchaSrc.length > 0) {
                $("#customCaptcha").prop("src", originalCaptchaSrc);
                var captchaSrc = $("#customCaptcha").prop("src");
                console.log('asdas', captchaSrc);
            }
            else {
                console.log('no length');
            }
        }, 800)


        $("#refreshCaptcha").on("click", function (e) {
            e.preventDefault();

            // Trigger the original postback to refresh CAPTCHA
            __doPostBack(
                'ctl00$ctl00$ContentContainer$MainContent$MainContent$captcha$CaptchaLinkButton',
                ''
            );

            // Wait a bit for the new CAPTCHA to be generated
            setTimeout(function () {
                // Get the new CAPTCHA src from the original image
                var newSrc = $("#ctl00_ctl00_ContentContainer_MainContent_MainContent_captcha_CaptchaImageUP").attr("src");

                // Update the custom CAPTCHA image
                $("#customCaptcha").attr("src", newSrc);
            }, 800); // 300ms delay is usually enough
        });

        $("#rgstrBtn").on("click", function (e) {
            // e.preventDefault(); // prevent default behavior of custom button
            $("#SubmitButton").click(); // trigger the original submit button
        });

        var errorText = $(".validation-summary-errors li, .alert-danger").text();

        if (errorText.trim() !== "") {
            console.log('*', errorText)
            $("#login-error").text(errorText).show();
        }
        $("#reg-email").on("input", function () {
            $("#EmailTextBox").val($(this).val());
        });

        $("#reg-username").on("input", function () {
            $("#UserNameTextBox").val($(this).val());
        });

        $("#reg-pass").on("input", function () {
            $("#PasswordTextBox").val($(this).val());
        });
        $("#reg-confirm").on("input", function () {
            $("#ConfirmPasswordTextBox").val($(this).val());
        });
        $("#captcha-code").on("input", function () {
            $("#ctl00_ctl00_ContentContainer_MainContent_MainContent_captcha_CaptchaTextBox").val($(this).val());
        });
    })
</script>"
}
